.row input.number {
  background: #222;
  border: 1px solid transparent;
  color: #1faaf2;
  min-height: 20px;
  padding-left: 5px;
  padding-right: 5px;
}

.row input.string {
  box-sizing: border-box;
  width: 165px;
}

.help-lists {
  display: -webkit-box;
  display: -ms-flexbox;
  display: flex;
  -ms-flex-pack: distribute;
      justify-content: space-around;
}

.help-list {
  list-style: none;
  margin: 0;
  padding: 0 0 10px;
  width: 350px;
}

.help-list li {
  margin-right: 40px;
}

.help-key-unit {
  line-height: 1.8;
  margin-right: 2em;
  padding: 5px 0;
}

.help-key {
  bottom: 2px;
  margin-right: 4px;
  min-width: 60px;
  position: relative;
}

.help-key span {
  background-color: #2e2e2e;
  background-repeat: repeat-x;
  border: 1px solid #666;
  border-radius: 3px;
  box-shadow: 0 0 5px #000;
  color: #999;
  display: inline-block;
  font-size: 12px;
  padding: 0 8px;
  text-align: center;
}

.help-key-def {
  color: #bbb;
  display: inline-block;
  margin-left: 1em;
}

.add-component {
  text-align: left;
}

.add-component .option {
  display: -webkit-box;
  display: -ms-flexbox;
  display: flex;
  -webkit-box-pack: justify;
      -ms-flex-pack: justify;
          justify-content: space-between;
}

.add-component .option span {
  color: #1faaf2;
}

.Select-menu-outer .is-focused span {
  color: #fff;
}

.add-component-container {
  -webkit-box-align: center;
      -ms-flex-align: center;
          align-items: center;
  background-color: #2b2b2b;
  display: -webkit-box;
  display: -ms-flexbox;
  display: flex;
  -webkit-box-pack: center;
      -ms-flex-pack: center;
          justify-content: center;
  padding: 10px;
}

.aregistry-button {
  font-size: 12px;
  margin-left: 10px;
  padding: 8px;
}

.aregistry-button:hover {
  background-color: #1faaf2;
}

.aregistry-button img {
  height: 20px;
  width: 20px;
}

.components .row .color_value {
  margin: 0 0 0 5px;
  width: 68px;
}

.assets.search {
  margin-top: 10px;
  width: 200px;
}

.assets.search .fa-search {
  top: 7px;
}

.gallery a.fa.texture-link {
  box-shadow: 0 0 14px -1px rgba(0, 0, 0, 0.75);
  position: fixed;
}

.outliner .id {
  color: #ccc;
}

.outliner .option.active .id {
  color: #fff;
}

.outliner .collasespace {
  color: #eee;
  display: inline-block;
  text-align: center;
  width: 14px;
}

.outliner .fa-eye {
  color: #bbb;
}

.outliner .option {
  white-space: pre;
}

.option span:first-child {
  overflow: hidden;
  text-overflow: ellipsis;
}

.outliner .option.novisible span,
.outliner .option.novisible .fa,
.outliner .option.novisible .collasespace,
.outliner .option.novisible .id {
  color: #575757;
}

.outliner .option .icons a.button {
  color: #fff;
}

.toggle-sidebar {
  -webkit-box-align: center;
      -ms-flex-align: center;
          align-items: center;
  display: -webkit-box;
  display: -ms-flexbox;
  display: flex;
  height: 100%;
  position: absolute;
  z-index: 9998;
}

.toggle-sidebar.left {
  left: 0;
}

.toggle-sidebar.right {
  right: 0;
}

.toggle-sidebar a {
  background-color: #262626;
  color: #bcbcbc;
  padding: 5px;
  z-index: 9998;
}

.toggle-sidebar a:hover {
  background-color: #1faaf2;
  color: #fff;
}

/* Dropdown menu */

.dropbtn {
  border: none;
  color: white;
  cursor: pointer;
}

.dropdown {
  display: inline-block;
  position: relative;
}

.dropdown-content {
  background-color: #f9f9f9;
  box-shadow: 0 8px 16px 0 rgba(0, 0, 0, 0.2);
  display: none;
  left: 8px;
  min-width: 38px;
  position: absolute;
  z-index: 999;
}

.dropdown-content a {
  background-color: #232323;
  color: #7d7d7d;
  display: block;
  padding: 10px 14px;
  text-decoration: none;
}

.dropdown-content a:hover {
  background-color: #4ecbff;
  color: #fff;
}

.dropdown:hover .dropdown-content {
  display: block;
}

.dropdown:hover .dropbtn {
  color: #1faaf2;
}

.savedRecordings {
  display: inline-block;
  margin-top: 10px;
  vertical-align: middle;
  width: 80%;
}
